package com.alsa.alsacleanfleet.controller;import com.alsa.alsacleanfleet.dto.*;import com.alsa.alsacleanfleet.service.UtilisateurService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/utilisateurs") public class UtilisateurController{private final UtilisateurService s;public UtilisateurController(UtilisateurService s){this.s=s;}@GetMapping public List<UtilisateurResponseDTO> all(){return s.findAll();}@GetMapping("/{id}")public UtilisateurResponseDTO one(@PathVariable Long id){return s.findById(id);}@PostMapping public ResponseEntity<UtilisateurResponseDTO> add(@Valid @RequestBody UtilisateurRequestDTO d){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(d));}@PutMapping("/{id}")public UtilisateurResponseDTO edit(@PathVariable Long id,@Valid @RequestBody UtilisateurRequestDTO d){return s.update(id,d);}@DeleteMapping("/{id}")public ResponseEntity<Void> del(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
